// SSRF protection helper
function isSafeUrl(url) {
  try {
    const u = new URL(url);
    if (!['http:', 'https:'].includes(u.protocol)) return false;
    const h = u.hostname.toLowerCase();
    if (['localhost', '127.0.0.1', '::1', '0.0.0.0'].includes(h)) return false;
    if (/^(10\.|172\.(1[6-9]|2[0-9]|3[01])\.|192\.168\.|169\.254\.|fc|fd|fe80)/i.test(h)) return false;
    if (h === '169.254.169.254' || h.endsWith('.internal') || h.endsWith('.local')) return false;
    return true;
  } catch(e) { return false; }
}

let content = '';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  content = buf.toString('utf-8');
} catch(e) {}

if (!content.trim()) return [{ json: { noWork: true, reason: 'file not found or empty' } }];

const lines = content.split('\n');
const toProcess = [];
let ssrfBlocked = 0;
for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  const urlMatch = line.match(/https?:\/\/[^\s\)\]>]+/);
  if (!urlMatch || line.includes('[title::')) continue;
  const url = urlMatch[0].replace(/[.,;>]+$/, '');
  if (!isSafeUrl(url)) { ssrfBlocked++; continue; }
  toProcess.push({ url, lineIndex: i, originalLine: line });
}

// Randomize to prevent queue starvation (blocked domains at front)
const shuffled = toProcess.slice().sort(() => Math.random() - 0.5);
const batch = shuffled.slice(0, 8);
if (batch.length === 0) return [{ json: { noWork: true, reason: `all URLs enriched or blocked (${ssrfBlocked} SSRF-blocked)`, totalLines: lines.length } }];

return batch.map(item => ({ json: { ...item, fileLines: lines, totalUnenriched: toProcess.length, ssrfBlocked } }));

// Safely correlate HTTP responses with original parsed items
const responses = $input.all();
const originals = $('Parse Unenriched URLs').all();

return responses.map((resp, i) => {
  const html = (resp.json.data || resp.json.body || '').toString();
  const original = (originals[i] && originals[i].json) ? originals[i].json : {};
  let title = '', description = '';

  // Skip if fetch failed
  if (!html || html.length < 100) {
    return { json: { ...original, extractedTitle: '', extractedDescription: '', fetchSuccess: false } };
  }

  try {
    let m = html.match(/<meta[^>]+property=["']og:title["'][^>]+content=["']([^"']{1,200})["']/i)
           || html.match(/<meta[^>]+content=["']([^"']{1,200})["'][^>]+property=["']og:title["']/i);
    if (m) title = m[1].trim();
    if (!title) {
      m = html.match(/<title[^>]*>([^<]{1,200})<\/title>/i);
      if (m) title = m[1].trim().replace(/\s+/g, ' ');
    }
    m = html.match(/<meta[^>]+property=["']og:description["'][^>]+content=["']([^"']{1,300})["']/i)
      || html.match(/<meta[^>]+content=["']([^"']{1,300})["'][^>]+property=["']og:description["']/i)
      || html.match(/<meta[^>]+name=["']description["'][^>]+content=["']([^"']{1,300})["']/i)
      || html.match(/<meta[^>]+content=["']([^"']{1,300})["'][^>]+name=["']description["']/i);
    if (m) description = m[1].trim().replace(/\s+/g, ' ').slice(0, 120);
  } catch(e) {}

  title = (title || '').replace(/[|\[\]]/g, '-').replace(/\s+/g, ' ').trim().slice(0, 100);
  if (!title) title = (original.url || 'Link').replace(/https?:\/\/([^/]+).*/, '$1');

  return { json: { ...original, extractedTitle: title, extractedDescription: description, fetchSuccess: true } };
});

const enrichedItems = $input.all();
if (!enrichedItems || !enrichedItems.length || !enrichedItems[0].json.fileLines) {
  return [{ json: { skipped: true, reason: 'no enriched items or missing fileLines' } }];
}

const fileLines = enrichedItems[0].json.fileLines || [];
const today = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });

const replacements = {};
for (const item of enrichedItems) {
  const { lineIndex, originalLine, url, extractedTitle, extractedDescription } = item.json;
  if (lineIndex === undefined || !extractedTitle) continue;
  let enriched = originalLine;
  if (!enriched.includes('[title::')) {
    const titleTag = ` [title:: ${extractedTitle}]`;
    const descTag = extractedDescription ? ` [description:: ${extractedDescription.slice(0, 100)}]` : '';
    enriched = enriched.trimEnd() + titleTag + descTag;
  }
  replacements[lineIndex] = enriched;
}

const newLines = fileLines.map((line, i) => replacements[i] !== undefined ? replacements[i] : line);
const newContent = newLines.join('\n');
const enrichedCount = Object.keys(replacements).length;

const buf = Buffer.from(newContent, 'utf-8');
const logContent = JSON.stringify({
  workflow: 'link-enricher', run_date: today,
  finished_at: new Date().toISOString(), status: 'success',
  urls_enriched: enrichedCount,
  total_unenriched_before: enrichedItems[0].json.totalUnenriched || 0
}, null, 2);
const logBuf = Buffer.from(logContent, 'utf-8');
const logKey = `99_System/logs/link-enricher-${today}.json`;

return [{ json: {
  fileKey: '00_Inbox/articles-to-process.md', enrichedCount, today, logKey
}, binary: {
  articleFile: { data: buf.toString('base64'), mimeType: 'text/markdown; charset=utf-8', fileName: 'articles-to-process.md', fileExtension: 'md', fileSize: buf.length },
  logFile: { data: logBuf.toString('base64'), mimeType: 'application/json', fileName: logKey.split('/').pop(), fileExtension: 'json', fileSize: logBuf.length }
}}];
